function catalog(){const map=new Map([...CATALOG,...EXTRA_CATALOG].map(x=>[x.id,{...x}]));data.customCatalog.forEach(x=>map.set(x.id,{...(map.get(x.id)||{}),...x}));return [...map.values()]}
function productByName(name){return catalog().find(p=>p.name.toLowerCase()===String(name).toLowerCase())}
function personalAverage(id,store){const h=data.priceHistory.filter(x=>x.productId===id&&x.store===store);return h.length?h.reduce((s,x)=>s+x.unitActual,0)/h.length:null}
function currentUnitPrice(x){const p=catalog().find(v=>v.id===x.productId);return personalAverage(x.productId,data.preferredStore)??p?.[data.preferredStore]??x.unitPrice??0}
function renderAll(){renderHome();renderTasks();renderMarket();renderRecipes();renderStats();renderRecords();document.getElementById('catalogCount').textContent=`${catalog().length} productos editables`;document.querySelectorAll('.store-tab').forEach(b=>b.classList.toggle('active',b.dataset.store===data.preferredStore))}
function renderHome(){const pendingT=data.tasks.filter(x=>!x.done),pendingS=data.shopping.filter(x=>!x.done),est=pendingS.reduce((s,x)=>s+x.qty*currentUnitPrice(x),0),month=today().slice(0,7),exp=data.expenses.filter(x=>x.date?.startsWith(month)).reduce((s,x)=>s+Number(x.amount),0),done=data.tasks.filter(x=>x.done).length+data.shopping.filter(x=>x.done).length,total=data.tasks.length+data.shopping.length,pct=total?Math.round(done/total*100):100;mTasks.textContent=pendingT.length;mShopping.textContent=pendingS.length;mMarket.textContent=money(est);mExpenses.textContent=money(exp);heroText.textContent=pct===100?'Todo bajo control.':`${pct}% de sus pendientes completados.`;heroProgress.style.width=pct+'%';const next=[...pendingT.map(x=>({...x,type:'task'})),...pendingS.map(x=>({...x,type:'shopping'}))].slice(0,5);homeList.innerHTML=next.length?next.map(x=>itemHTML(x,x.type)).join(''):'<div class="empty">No tienen pendientes. ¡Buen trabajo! 🎉</div>';const insightsData=[];if(est>data.budget)insightsData.push(['⚠️','Presupuesto excedido',`El mercado supera el presupuesto en ${money(est-data.budget)}.`]);const favMissing=data.favorites.filter(id=>!data.shopping.some(x=>x.productId===id&&!x.done)).slice(0,3).map(id=>catalog().find(p=>p.id===id)?.name).filter(Boolean);if(favMissing.length)insightsData.push(['⭐','Favoritos habituales',`Podrían necesitar: ${favMissing.join(', ')}.`]);if(data.priceHistory.length)insightsData.push(['🧠','Estimaciones personalizadas',`La app ya aprendió de ${data.priceHistory.length} compras reales.`]);if(!insightsData.length)insightsData.push(['💡','Consejo Pro','Registra precios reales para mejorar automáticamente los próximos presupuestos.']);insights.innerHTML=insightsData.map(i=>`<div class="card insight"><div class="insight-icon">${i[0]}</div><div><b>${i[1]}</b><div class="meta">${i[2]}</div></div></div>`).join('')}
function itemHTML(x,type){if(type==='task')return `<div class="card item ${x.done?'done':''}"><button class="check ${x.done?'done':''}" onclick="toggleTask('${x.id}')">${x.done?'✓':''}</button><div class="main"><div class="title">${esc(x.title)}</div><div class="meta"><span class="pill">${esc(x.assigned)}</span><span>${esc(x.category)}</span><span>${esc(x.date||'')}</span></div></div><button class="mini" onclick="removeItem('task','${x.id}')">⋯</button></div>`;const price=currentUnitPrice(x),total=x.qty*price,actual=x.actualTotal;return `<div class="card item ${x.done?'done':''}"><button class="check ${x.done?'done':''}" onclick="${x.done?`reopenPurchase('${x.id}')`:`openPurchase('${x.id}')`}">${x.done?'✓':''}</button><div class="main"><div class="title">${esc(x.title)} ${data.favorites.includes(x.productId)?'<span class="fav">★</span>':''}</div><div class="meta"><span class="pill">${x.qty} ${esc(x.unit)}</span><span>${esc(STORE_LABEL[data.preferredStore])}</span><span>${x.done?'Pagado '+money(actual):'Estimado '+money(total)}</span></div></div><div class="actions"><button class="mini" onclick="toggleFavorite('${x.productId}')">${data.favorites.includes(x.productId)?'★':'☆'}</button><button class="mini" onclick="removeItem('shopping','${x.id}')">⋯</button></div></div>`}
function renderTasks(){let a=data.tasks;if(taskFilter==='pending')a=a.filter(x=>!x.done);else if(taskFilter!=='all')a=a.filter(x=>x.assigned===taskFilter);taskList.innerHTML=a.length?a.map(x=>itemHTML(x,'task')).join(''):'<div class="empty">No hay tareas en esta vista.</div>'}
function renderMarket(){let a=data.shopping.filter(x=>x.title.toLowerCase().includes(marketQuery.toLowerCase()));if(shopFilter==='pending')a=a.filter(x=>!x.done);if(shopFilter==='done')a=a.filter(x=>x.done);if(shopFilter==='favorites')a=a.filter(x=>data.favorites.includes(x.productId));shoppingList.innerHTML=a.length?a.map(x=>itemHTML(x,'shopping')).join(''):'<div class="empty">Agrega productos o una receta completa con el botón ＋.</div>';const pend=data.shopping.filter(x=>!x.done),vals=pend.map(x=>{const p=catalog().find(v=>v.id===x.productId),u=currentUnitPrice(x);return {prob:x.qty*u,min:x.qty*u*(p?.minFactor||.85),max:x.qty*u*(p?.maxFactor||1.18)}}),sum=k=>vals.reduce((s,v)=>s+v[k],0),prob=sum('prob'),bal=data.budget-prob;budgetValue.textContent=money(data.budget);estimatedValue.textContent=money(prob);minValue.textContent=money(sum('min'));probValue.textContent=money(prob);maxValue.textContent=money(sum('max'));balanceValue.textContent=money(Math.abs(bal));balanceValue.className=bal<0?'danger':'';balanceLabel.textContent=bal<0?'Presupuesto excedido':'Saldo restante'}
function renderRecipes(){const q=recipeSearch.value?.toLowerCase()||'',a=RECIPES.filter(r=>r.name.toLowerCase().includes(q));recipeGrid.innerHTML=a.map(r=>`<div class="recipe"><div class="emoji">${r.emoji}</div><h3>${r.name}</h3><p>${r.desc}<br>${r.items.length} ingredientes</p><button onclick="addRecipe('${r.id}')">Agregar ingredientes</button></div>`).join('')}
function addRecipe(id){const r=RECIPES.find(x=>x.id===id);if(!r)return;let added=0;r.items.forEach(([name,qty])=>{const p=productByName(name);if(!p)return;const existing=data.shopping.find(x=>x.productId===p.id&&!x.done);if(existing)existing.qty+=qty;else data.shopping.unshift({id:uid(),productId:p.id,title:p.name,qty,unit:p.unit,unitPrice:p[data.preferredStore],store:data.preferredStore,assigned:'Ambos',category:p.category,done:false});added++});save();showView('market');toast(`${added} ingredientes de ${r.name} agregados`)}
function renderStats(){sPurchases.textContent=data.priceHistory.length;const savings=data.priceHistory.reduce((s,x)=>s+(x.estimatedTotal-x.actualTotal),0);sSavings.textContent=money(savings);sSavings.className=savings<0?'danger':'';const months=[];for(let i=5;i>=0;i--){const d=new Date();d.setMonth(d.getMonth()-i);months.push(d.toISOString().slice(0,7))}const vals=months.map(m=>data.expenses.filter(x=>x.date?.startsWith(m)).reduce((s,x)=>s+Number(x.amount),0)),max=Math.max(...vals,1);monthChart.innerHTML=months.map((m,i)=>`<div class="bar-wrap"><div class="bar" style="height:${Math.max(3,vals[i]/max*100)}%" title="${money(vals[i])}"></div><small>${new Date(m+'-02').toLocaleDateString('es-PE',{month:'short'})}</small></div>`).join('');const by={};data.priceHistory.forEach(x=>{const p=catalog().find(v=>v.id===x.productId);by[p?.category||'Otros']=(by[p?.category||'Otros']||0)+x.actualTotal});categoryStats.innerHTML=Object.entries(by).sort((a,b)=>b[1]-a[1]).slice(0,8).map(([k,v])=>`<div class="card"><div class="budget-line"><b>${esc(k)}</b><strong>${money(v)}</strong></div></div>`).join('')||'<div class="empty">Aún no hay compras registradas.</div>';priceHistory.innerHTML=data.priceHistory.slice(0,20).map(x=>`<div class="card"><div class="title">${esc(x.title)}</div><div class="meta"><span>${esc(x.date)}</span><span>${esc(x.place||STORE_LABEL[x.store])}</span><span>${money(x.unitActual)} / ${esc(x.unit)}</span></div></div>`).join('')||'<div class="empty">Registra una compra para comenzar el historial.</div>'}
function renderRecords(){expenseList.innerHTML=data.expenses.length?data.expenses.slice(0,30).map(x=>`<div class="card"><div class="item"><div class="insight-icon">💸</div><div class="main"><div class="title">${esc(x.title)}</div><div class="meta"><span>${esc(x.date||'Sin fecha')}</span><span>${esc(x.paidBy||'Sin responsable')}</span></div><strong style="display:block;margin-top:8px">${money(x.amount)}</strong></div><div class="actions"><button class="mini" aria-label="Editar gasto" onclick="editRecord('expense','${x.id}')">✎</button><button class="mini" aria-label="Eliminar gasto" onclick="deleteRecord('expense','${x.id}')">🗑️</button></div></div></div>`).join(''):'<div class="empty">Sin gastos.</div>';noteList.innerHTML=data.notes.length?data.notes.map(x=>`<div class="card"><div class="item"><div class="insight-icon">📝</div><div class="main"><div class="title">${esc(x.title)}</div><p class="meta" style="white-space:pre-wrap">${esc(x.text)}</p></div><div class="actions"><button class="mini" aria-label="Editar nota" onclick="editRecord('note','${x.id}')">✎</button><button class="mini" aria-label="Eliminar nota" onclick="deleteRecord('note','${x.id}')">🗑️</button></div></div></div>`).join(''):'<div class="empty">Sin notas.</div>'}
function toggleTask(id){const x=data.tasks.find(v=>v.id===id);if(x){x.done=!x.done;save()}}function removeItem(type,id){if(!confirm('¿Eliminar este elemento?'))return;data[type==='task'?'tasks':'shopping']=data[type==='task'?'tasks':'shopping'].filter(x=>x.id!==id);save()}function toggleFavorite(id){if(!id)return;data.favorites=data.favorites.includes(id)?data.favorites.filter(x=>x!==id):[...data.favorites,id];save();toast(data.favorites.includes(id)?'Agregado a favoritos':'Eliminado de favoritos')}
function showView(name){document.querySelectorAll('.view').forEach(v=>v.classList.toggle('active',v.id===name+'View'));document.querySelectorAll('.nav button').forEach(b=>b.classList.toggle('active',b.dataset.view===name));const titles={home:['Nuestro Espacio Ultra','Hogar, mercado y presupuesto'],tasks:['Tareas','Pendientes compartidos'],market:['Mercado inteligente','Precios y presupuesto'],recipes:['Recetas','Agrega ingredientes en un toque'],stats:['Estadísticas','Gastos y aprendizaje'],more:['Más','Catálogo y respaldos']};pageTitle.textContent=titles[name][0];pageSubtitle.textContent=titles[name][1];fab.style.display=['home','tasks','market'].includes(name)?'block':'none';window.scrollTo(0,0)}
document.querySelectorAll('.nav button').forEach(b=>b.onclick=()=>showView(b.dataset.view));fab.onclick=()=>typeModal.classList.add('open');document.querySelectorAll('.type').forEach(b=>b.onclick=()=>openForm(b.dataset.type));function closeModal(id){document.getElementById(id).classList.remove('open')}
function openForm(type,id=''){currentType=type;currentEditId=id||'';closeModal('typeModal');const editing=Boolean(currentEditId);formTitle.textContent=editing?{task:'Editar tarea',shopping:'Editar producto',expense:'Editar gasto',note:'Editar nota'}[type]:{task:'Nueva tarea',shopping:'Agregar producto',expense:'Nuevo gasto',note:'Nueva nota'}[type];if(type==='task')formFields.innerHTML=`<div class="field"><label>Tarea</label><input name="title" required placeholder="Ej. Pagar internet"></div><div class="row"><div class="field"><label>Fecha</label><input name="date" type="date" value="${today()}"></div><div class="field"><label>Prioridad</label><select name="priority"><option>Alta</option><option selected>Media</option><option>Baja</option></select></div></div><div class="row"><div class="field"><label>Responsable</label><select name="assigned"><option>Yo</option><option>Mi pareja</option><option>Ambos</option></select></div><div class="field"><label>Categoría</label><input name="category" value="Hogar"></div></div>`;if(type==='shopping')formFields.innerHTML=`<div class="field"><label>Producto</label><input id="productInput" name="title" autocomplete="off" required placeholder="Ej. Sandía"><div class="suggestions" id="suggestions"></div></div><input type="hidden" name="productId" id="productId"><div class="row"><div class="field"><label>Cantidad</label><input id="qtyInput" name="qty" type="number" min="0.01" step="0.01" value="1" required></div><div class="field"><label>Unidad</label><input id="unitInput" name="unit" value="unidad" required></div></div><div class="row"><div class="field"><label>Comprar en</label><select id="storeInput" name="store"><option value="market">Mercado</option><option value="supermarket">Supermercado</option><option value="wholesale">Mayorista</option></select></div><div class="field"><label>Responsable</label><select name="assigned"><option>Yo</option><option>Mi pareja</option><option>Ambos</option></select></div></div><div id="estimateBox" class="estimate"><div class="estimate-head"><span>Precio estimado</span><strong id="estimateTotal">S/ 0.00</strong></div><div class="meta" id="estimateMeta">Busca y selecciona un producto.</div></div><div class="field"><label>Precio por unidad/peso</label><input id="manualPrice" name="unitPrice" type="number" min="0" step="0.01" value="0" required></div><div class="field"><label>Categoría</label><input id="categoryInput" name="category" value="Otros"></div>`;if(type==='expense')formFields.innerHTML=`<div class="field"><label>Descripción</label><input name="title" required></div><div class="row"><div class="field"><label>Monto</label><input name="amount" type="number" min="0" step="0.01" required></div><div class="field"><label>Fecha</label><input name="date" type="date" value="${today()}"></div></div><div class="field"><label>Pagó</label><select name="paidBy"><option>Yo</option><option>Mi pareja</option><option>Ambos</option></select></div>`;if(type==='note')formFields.innerHTML=`<div class="field"><label>Título</label><input name="title" required></div><div class="field"><label>Contenido</label><textarea name="text" required></textarea></div>`;formModal.classList.add('open');if(type==='shopping')setupProductForm();if(editing){const source=type==='expense'?data.expenses:type==='note'?data.notes:type==='task'?data.tasks:data.shopping;const item=source.find(x=>x.id===currentEditId);if(item){Object.entries(item).forEach(([k,v])=>{const el=itemForm.elements[k];if(el&&v!==undefined&&v!==null){if(el.type==='checkbox')el.checked=Boolean(v);else el.value=v}});if(type==='shopping'){setTimeout(()=>{updateEstimate?.();const w=document.getElementById('weightKg');if(w&&item.weightKg!=null)w.value=item.weightKg},0)}}}}
function setupProductForm(){storeInput.value=data.preferredStore;const update=()=>{const q=Number(qtyInput.value||0),p=Number(manualPrice.value||0);estimateTotal.textContent=money(q*p);const prod=catalog().find(x=>x.id===productId.value);estimateMeta.textContent=prod?`${STORE_LABEL[storeInput.value]} · rango ${money(q*p*prod.minFactor)} a ${money(q*p*prod.maxFactor)}`:'Precio manual para un producto nuevo.'};productInput.oninput=()=>{const q=productInput.value.toLowerCase().trim(),a=q?catalog().filter(x=>x.name.toLowerCase().includes(q)).slice(0,10):[];suggestions.innerHTML=a.map(p=>`<button type="button" class="suggestion" data-id="${p.id}"><b>${esc(p.name)}</b><div class="meta">${esc(p.category)} · ${esc(p.unit)} · ${money(personalAverage(p.id,storeInput.value)??p[storeInput.value])}</div></button>`).join('');suggestions.classList.toggle('show',!!a.length)};suggestions.onclick=e=>{const b=e.target.closest('[data-id]');if(b)selectProduct(b.dataset.id)};storeInput.onchange=()=>{const p=catalog().find(x=>x.id===productId.value);if(p)manualPrice.value=(personalAverage(p.id,storeInput.value)??p[storeInput.value]).toFixed(2);update()};qtyInput.oninput=manualPrice.oninput=update;update()}
function selectProduct(id){const p=catalog().find(x=>x.id===id);if(!p)return;productId.value=p.id;productInput.value=p.name;unitInput.value=p.unit;categoryInput.value=p.category;manualPrice.value=(personalAverage(p.id,storeInput.value)??p[storeInput.value]).toFixed(2);suggestions.classList.remove('show');qtyInput.dispatchEvent(new Event('input'))}
itemForm.onsubmit=e=>{e.preventDefault();const o=Object.fromEntries(new FormData(e.target));const editing=Boolean(currentEditId);o.id=currentEditId||uid();if(currentType==='task'){const old=data.tasks.find(x=>x.id===o.id);o.done=old?.done||false;if(editing&&old)Object.assign(old,o);else data.tasks.unshift(o)}else if(currentType==='shopping'){o.qty=Number(o.qty);o.unitPrice=Number(o.unitPrice);const old=data.shopping.find(x=>x.id===o.id);o.done=old?.done||false;if(!o.productId){const id='custom_'+uid();const p={id,name:o.title,category:o.category,unit:o.unit,market:o.unitPrice,supermarket:o.unitPrice,wholesale:o.unitPrice,minFactor:.85,maxFactor:1.18};data.customCatalog.push(p);o.productId=id}if(editing&&old)Object.assign(old,o);else data.shopping.unshift(o)}else if(currentType==='expense'){o.amount=Number(o.amount);const old=data.expenses.find(x=>x.id===o.id);if(editing&&old)Object.assign(old,o);else data.expenses.unshift(o)}else{const old=data.notes.find(x=>x.id===o.id);if(editing&&old)Object.assign(old,o);else data.notes.unshift(o)}currentEditId='';closeModal('formModal');save();if(document.getElementById('recordsModal').classList.contains('open'))renderRecords();toast(editing?'Cambios guardados':'Guardado correctamente')}
function openPurchase(id){const x=data.shopping.find(v=>v.id===id);if(!x)return;purchaseForm.id.value=id;purchaseForm.actualTotal.value=(x.qty*currentUnitPrice(x)).toFixed(2);purchaseForm.place.value=STORE_LABEL[data.preferredStore];purchaseForm.date.value=today();purchaseSummary.innerHTML=`<b>${esc(x.title)}</b><div class="meta">${x.qty} ${esc(x.unit)} · estimado ${money(x.qty*currentUnitPrice(x))}</div>`;purchaseModal.classList.add('open')}function reopenPurchase(id){const x=data.shopping.find(v=>v.id===id);if(x&&confirm('¿Marcar nuevamente como pendiente?')){x.done=false;save()}}
purchaseForm.onsubmit=e=>{e.preventDefault();const o=Object.fromEntries(new FormData(e.target)),x=data.shopping.find(v=>v.id===o.id);if(!x)return;const est=x.qty*currentUnitPrice(x);x.done=true;x.actualTotal=Number(o.actualTotal);x.purchaseDate=o.date;data.priceHistory.unshift({id:uid(),productId:x.productId,title:x.title,qty:x.qty,unit:x.unit,store:data.preferredStore,estimatedTotal:est,actualTotal:Number(o.actualTotal),unitActual:Number(o.actualTotal)/x.qty,place:o.place,date:o.date});data.expenses.unshift({id:uid(),title:'Mercado: '+x.title,amount:Number(o.actualTotal),date:o.date,paidBy:x.assigned||'Ambos'});closeModal('purchaseModal');save();toast('Precio real aprendido')}
function editBudget(){const v=prompt('Presupuesto del mercado:',data.budget);if(v!==null&&!isNaN(v)){data.budget=Number(v);save()}}taskFilters.onclick=e=>{const b=e.target.closest('.filter');if(!b)return;taskFilter=b.dataset.filter;taskFilters.querySelectorAll('.filter').forEach(x=>x.classList.toggle('active',x===b));renderTasks()};shopFilters.onclick=e=>{const b=e.target.closest('.filter');if(!b)return;shopFilter=b.dataset.filter;shopFilters.querySelectorAll('.filter').forEach(x=>x.classList.toggle('active',x===b));renderMarket()};storeTabs.onclick=e=>{const b=e.target.closest('.store-tab');if(!b)return;data.preferredStore=b.dataset.store;save();toast('Precios: '+STORE_LABEL[data.preferredStore])};marketSearch.oninput=()=>{marketQuery=marketSearch.value;renderMarket()};recipeSearch.oninput=renderRecipes;
function openCatalog(){catalogModal.classList.add('open');renderCatalog()}function renderCatalog(){const q=catalogSearch.value?.toLowerCase()||'',a=catalog().filter(p=>(catalogCategory==='Todos'||p.category===catalogCategory)&&p.name.toLowerCase().includes(q)).slice(0,100);catalogList.innerHTML=a.map(p=>`<div class="card"><div class="item"><button class="mini fav" onclick="toggleFavorite('${p.id}')">${data.favorites.includes(p.id)?'★':'☆'}</button><div class="main"><div class="title">${esc(p.name)}</div><div class="meta"><span class="pill">${esc(p.category)}</span><span>${esc(p.unit)}</span><span>M ${money(p.market)} · S ${money(p.supermarket)} · My ${money(p.wholesale)}</span></div></div><button class="text-btn" onclick="editCatalogProduct('${p.id}')">Editar</button></div></div>`).join('')||'<div class="empty">Sin resultados.</div>'}function initCatalogChips(){const cats=['Todos',...new Set(catalog().map(p=>p.category))];catalogChips.innerHTML=cats.map(c=>`<button class="chip ${c==='Todos'?'active':''}" data-cat="${esc(c)}">${esc(c)}</button>`).join('')}catalogChips.onclick=e=>{const b=e.target.closest('.chip');if(!b)return;catalogCategory=b.dataset.cat;catalogChips.querySelectorAll('.chip').forEach(x=>x.classList.toggle('active',x===b));renderCatalog()};catalogSearch.oninput=renderCatalog;function editCatalogProduct(id){const base=catalog().find(x=>x.id===id);if(!base)return;const m=prompt(`Precio de mercado para ${base.name}:`,base.market);if(m===null||isNaN(m))return;const s=prompt('Precio de supermercado:',base.supermarket);if(s===null||isNaN(s))return;const w=prompt('Precio mayorista:',base.wholesale);if(w===null||isNaN(w))return;let p=data.customCatalog.find(x=>x.id===id);if(!p){p={...base};data.customCatalog.push(p)}p.market=Number(m);p.supermarket=Number(s);p.wholesale=Number(w);save();renderCatalog();toast('Precios actualizados')}
function showFavorites(){showView('market');shopFilter='favorites';shopFilters.querySelectorAll('.filter').forEach(x=>x.classList.toggle('active',x.dataset.filter==='favorites'));renderMarket()}function openRecords(){recordsModal.classList.add('open');renderRecords()}function editRecord(type,id){openForm(type,id)}function deleteRecord(type,id){const label=type==='expense'?'este gasto':'esta nota';if(!confirm(`¿Eliminar ${label}?`))return;const key=type==='expense'?'expenses':'notes';data[key]=data[key].filter(x=>x.id!==id);save();renderRecords();toast(type==='expense'?'Gasto eliminado':'Nota eliminada')}
function toggleTheme(){data.theme=data.theme==='dark'?'light':'dark';save()}function applyTheme(){document.body.classList.toggle('dark',data.theme==='dark');themeBtn.textContent=data.theme==='dark'?'☀️':'🌙'}themeBtn.onclick=toggleTheme;function exportData(){const a=document.createElement('a'),b=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});a.href=URL.createObjectURL(b);a.download='nuestro-espacio-pro-respaldo.json';a.click();URL.revokeObjectURL(a.href);toast('Respaldo descargado')}importFile.onchange=e=>{const f=e.target.files[0];if(!f)return;const r=new FileReader();r.onload=()=>{try{data=migrate(JSON.parse(r.result));save();toast('Respaldo restaurado')}catch{alert('Archivo inválido')}};r.readAsText(f)};function resetData(){if(confirm('¿Eliminar todos los datos locales?')){data=structuredClone(seed);save();toast('Aplicación reiniciada')}}function toast(t){const el=document.getElementById('toast');el.textContent=t;el.classList.add('show');clearTimeout(window.__tt);window.__tt=setTimeout(()=>el.classList.remove('show'),2200)}document.querySelectorAll('.modal').forEach(m=>m.addEventListener('click',e=>{if(e.target===m)m.classList.remove('open')}));
// === MÓDULO PRO: GASTOS FIJOS Y CARGA ESTIMADA ===
const unitWeightDefaults={kg:1,litro:1,'500 g':.5,'250 g':.25,'100 g':.1,docena:.75,unidad:.35,paquete:.4,bolsa:.3,caja:.5,botella:1.1,lata:.4,frasco:.5,atado:.25,juego:1.5,par:.5};
function normalizedMonthlyAmount(x){const a=Number(x.amount||0);return x.frequency==='weekly'?a*4.33:x.frequency==='biweekly'?a*2:x.frequency==='yearly'?a/12:a}
function fixedMonthlyTotal(){return (data.fixedExpenses||[]).filter(x=>x.active!==false).reduce((s,x)=>s+normalizedMonthlyAmount(x),0)}
function estimatedItemWeight(x){if(Number.isFinite(Number(x.weightKg))&&Number(x.weightKg)>=0)return Number(x.weightKg);const u=String(x.unit||'').toLowerCase();if(u==='kg')return Number(x.qty||0);if(u.includes('litro'))return Number(x.qty||0);const per=unitWeightDefaults[u]??.35;return Number(x.qty||0)*per}
function calculateLoad(){const p=data.shopping.filter(x=>!x.done),weights=p.map(x=>({x,w:estimatedItemWeight(x)})),total=weights.reduce((s,o)=>s+o.w,0),known=weights.filter(o=>o.w>0).length,unknown=weights.filter(o=>!o.w).length;return{total,known,unknown,bags:total?Math.max(1,Math.ceil(total/6)):0}}
function renderFixedHome(){const el=document.getElementById('fixedHomeSummary');if(!el)return;const total=fixedMonthlyTotal(),market=data.shopping.filter(x=>!x.done).reduce((s,x)=>s+x.qty*currentUnitPrice(x),0);el.innerHTML=`<div class="budget-top"><div><small>Compromisos del mes</small><strong>${money(total)}</strong></div><span style="font-size:27px">🏠</span></div><div class="meta"><span>Gastos fijos activos: ${(data.fixedExpenses||[]).filter(x=>x.active!==false).length}</span><span>Fijos + mercado pendiente: ${money(total+market)}</span></div>`}
function currentMonthVariableExpenses(){const month=today().slice(0,7);return (data.expenses||[]).filter(x=>x.date?.startsWith(month)).reduce((s,x)=>s+Number(x.amount||0),0)}
function pendingMarketTotal(){return (data.shopping||[]).filter(x=>!x.done).reduce((s,x)=>s+Number(x.qty||0)*currentUnitPrice(x),0)}
function renderIncomeSummary(){const el=document.getElementById('incomeHomeSummary');if(!el)return;const income=Number(data.monthlyIncome||0),fixed=fixedMonthlyTotal(),market=pendingMarketTotal(),other=currentMonthVariableExpenses(),commitments=fixed+market+other,balance=income-commitments;el.innerHTML=`<div class="budget-top"><div><small>SUELDO FIJO MENSUAL</small><strong>${money(income)}</strong></div><button class="text-btn" style="color:#fff" onclick="editMonthlyIncome()">Editar</button></div><div class="income-breakdown"><div class="income-cell"><small>Gastos fijos</small><b>− ${money(fixed)}</b></div><div class="income-cell"><small>Mercado pendiente</small><b>− ${money(market)}</b></div><div class="income-cell"><small>Otros gastos del mes</small><b>− ${money(other)}</b></div><div class="income-cell"><small>Compromisos totales</small><b>${money(commitments)}</b></div></div><div class="income-balance ${balance<0?'negative':''}"><span>${income?'Disponible estimado':'Configura tu sueldo'}</span><strong>${income?money(balance):'—'}</strong></div><div class="meta">El mercado pendiente es una proyección; al comprarlo puede pasar a gastos reales.</div>`}
function editMonthlyIncome(){const v=prompt('Ingresa tu sueldo fijo mensual en soles:',Number(data.monthlyIncome||0));if(v===null)return;const n=Number(String(v).replace(',','.'));if(!Number.isFinite(n)||n<0){toast('Ingresa un monto válido');return}data.monthlyIncome=n;save();toast('Sueldo mensual actualizado')}
function renderLoad(){const r=calculateLoad();if(!document.getElementById('loadKg'))return;loadKg.textContent=r.total.toFixed(r.total<10?1:0)+' kg';loadBags.textContent=r.bags+(r.bags===1?' bolsa':' bolsas');loadItems.textContent=r.known;loadWarning.textContent=r.unknown?`${r.unknown} producto(s) no tienen peso estimado. Puedes editarlo al agregarlos.`:'Cálculo referencial. Considera envases, bolsas y variación del producto.'}
const __renderAll=renderAll;renderAll=function(){__renderAll();renderFixedHome();renderIncomeSummary();renderLoad();if(document.getElementById('fixedModal')?.classList.contains('open'))renderFixedExpenses()}
const __renderHome=renderHome;renderHome=function(){__renderHome();const total=fixedMonthlyTotal();mExpenses.textContent=money(data.expenses.filter(x=>x.date?.startsWith(today().slice(0,7))).reduce((s,x)=>s+Number(x.amount),0)+total)}
const __renderMarket=renderMarket;renderMarket=function(){__renderMarket();renderLoad()}
const __openForm=openForm;openForm=function(type,id=''){__openForm(type,id);if(type==='shopping'){const cat=document.getElementById('categoryInput')?.closest('.field');if(cat&&!document.getElementById('weightKg'))cat.insertAdjacentHTML('afterend',`<div class="field"><label>Peso total estimado (kg)</label><input id="weightKg" name="weightKg" type="number" min="0" step="0.01" placeholder="Se calcula automáticamente"><div class="tiny">Úsalo para saber cuánto cargarás. Puedes corregirlo manualmente.</div></div>`);const updateWeight=()=>{const p=catalog().find(x=>x.id===productId.value),q=Number(qtyInput.value||0),u=String(unitInput.value||p?.unit||'').toLowerCase();if(!weightKg.dataset.manual){weightKg.value=(u==='kg'||u.includes('litro')?q:q*(unitWeightDefaults[u]??.35)).toFixed(2)}};weightKg.oninput=()=>weightKg.dataset.manual='1';qtyInput.addEventListener('input',updateWeight);unitInput.addEventListener('input',updateWeight);setTimeout(updateWeight,0)}}
const __selectProduct=selectProduct;selectProduct=function(id){__selectProduct(id);const w=document.getElementById('weightKg');if(w){delete w.dataset.manual;const q=Number(qtyInput.value||0),u=String(unitInput.value||'').toLowerCase();w.value=(u==='kg'||u.includes('litro')?q:q*(unitWeightDefaults[u]??.35)).toFixed(2)}}
const __submit=itemForm.onsubmit;itemForm.onsubmit=function(e){if(currentType==='shopping'){const f=new FormData(e.target),w=f.get('weightKg');setTimeout(()=>{const newest=data.shopping[0];if(newest&&w!==null&&w!==''){newest.weightKg=Number(w);save()}},0)}return __submit.call(this,e)}
function openFixedExpenses(){fixedModal.classList.add('open');renderFixedExpenses()}
function renderFixedExpenses(){const a=data.fixedExpenses||[],total=fixedMonthlyTotal();fixedTotal.textContent=money(total);fixedDaily.textContent=`Equivale aproximadamente a ${money(total/30)} por día y ${money(total/4.33)} por semana.`;fixedList.innerHTML=a.length?a.sort((x,y)=>Number(x.dueDay)-Number(y.dueDay)).map(x=>`<div class="card fixed-item"><div class="item"><button class="check ${x.active!==false?'done':''}" onclick="toggleFixed('${x.id}')">${x.active!==false?'✓':''}</button><div class="main"><div class="title">${esc(x.title)}</div><div class="meta"><span class="pill">${esc(x.category)}</span><span>${money(normalizedMonthlyAmount(x))}/mes</span><span>día ${x.dueDay}</span><span>${esc(x.paidBy)}</span></div></div><div class="actions"><button class="mini" onclick="openFixedForm('${x.id}')">✎</button><button class="mini" onclick="deleteFixed('${x.id}')">×</button></div></div></div>`).join(''):'<div class="empty">Agrega alquiler, celular, pasajes, internet y otros pagos recurrentes.</div>'}
function openFixedForm(id=''){const x=(data.fixedExpenses||[]).find(v=>v.id===id);fixedForm.reset();fixedFormTitle.textContent=x?'Editar gasto fijo':'Nuevo gasto fijo';fixedForm.id.value=x?.id||'';fixedForm.title.value=x?.title||'';fixedForm.amount.value=x?.amount??'';fixedForm.dueDay.value=x?.dueDay||1;fixedForm.category.value=x?.category||'Vivienda';fixedForm.paidBy.value=x?.paidBy||'Ambos';fixedForm.frequency.value=x?.frequency||'monthly';fixedForm.active.checked=x?.active!==false;fixedFormModal.classList.add('open')}
fixedForm.onsubmit=e=>{e.preventDefault();const o=Object.fromEntries(new FormData(e.target));o.amount=Number(o.amount);o.dueDay=Number(o.dueDay);o.active=e.target.active.checked;const old=data.fixedExpenses.find(x=>x.id===o.id);if(old)Object.assign(old,o);else{if(!o.id)o.id=uid();data.fixedExpenses.push(o)}closeModal('fixedFormModal');save();fixedModal.classList.add('open');toast('Gasto fijo guardado')}
function toggleFixed(id){const x=data.fixedExpenses.find(v=>v.id===id);if(x){x.active=x.active===false;save()}}
function deleteFixed(id){if(confirm('¿Eliminar este gasto fijo?')){data.fixedExpenses=data.fixedExpenses.filter(x=>x.id!==id);save()}}

