data.pantry=data.pantry||[];data.wishlist=data.wishlist||[];data.savingsGoals=data.savingsGoals||[];data.mealPlan=data.mealPlan||{};data.events=data.events||[];data.barcodes=data.barcodes||{};data.ultraVersion=1;
const weekDays=['Lunes','Martes','Miércoles','Jueves','Viernes','Sábado','Domingo'];
function persistUltra(){localStorage.setItem('nuestroEspacioPro',JSON.stringify(data));renderUltraHome()}
function openUltra(){ultraModal.classList.add('open');renderUltraHome()}
function renderUltraHome(){
 const low=data.pantry.filter(x=>Number(x.qty)<=Number(x.minQty)).length;
 const goal=data.savingsGoals.reduce((s,x)=>s+Number(x.target||0),0),saved=data.savingsGoals.reduce((s,x)=>s+Number(x.saved||0),0);
 const upcoming=data.events.filter(x=>x.date>=today()).sort((a,b)=>a.date.localeCompare(b.date))[0];
 if(document.getElementById('ultraGrid')) ultraGrid.innerHTML=`
 <button class="ultra-card" onclick="openPantry()"><span class="uicon">🥫</span><b>Despensa</b><small>${data.pantry.length} productos · ${low} por reponer</small></button>
 <button class="ultra-card" onclick="openMeals()"><span class="uicon">🍽️</span><b>Menú semanal</b><small>${Object.values(data.mealPlan).filter(Boolean).length} días planificados</small></button>
 <button class="ultra-card" onclick="openWishlist()"><span class="uicon">✨</span><b>Lista de deseos</b><small>${data.wishlist.filter(x=>!x.done).length} pendientes</small></button>
 <button class="ultra-card" onclick="openGoals()"><span class="uicon">🎯</span><b>Metas de ahorro</b><small>${money(saved)} de ${money(goal)}</small></button>
 <button class="ultra-card" onclick="openCalendar()"><span class="uicon">📅</span><b>Agenda</b><small>${upcoming?esc(upcoming.title)+' · '+upcoming.date:'Sin próximos eventos'}</small></button>
 <button class="ultra-card" onclick="openScanner()"><span class="uicon">📷</span><b>Escáner</b><small>Código de barras con cámara o manual</small></button>
 <button class="ultra-card" onclick="requestNotifications()"><span class="uicon">🔔</span><b>Recordatorios</b><small>Activar avisos del navegador</small></button>
 <button class="ultra-card" onclick="openShare()"><span class="uicon">🔄</span><b>Compartir datos</b><small>Respaldo completo entre dispositivos</small></button>`;
 const more=document.getElementById('moreView'); if(more&&!document.getElementById('ultraEntry')){const d=document.createElement('div');d.id='ultraEntry';d.innerHTML=`<div class="section-head"><h2>Hogar inteligente</h2><span class="smart-badge">PRO ULTRA</span></div><div class="setting" onclick="openUltra()"><div><b>🏡 Centro del hogar</b><small>Despensa, menú, metas, deseos, agenda y escáner</small></div><b>›</b></div>`;more.prepend(d)}
}
function openPantry(){closeModal('ultraModal');pantryModal.classList.add('open');renderPantry()}
function renderPantry(){const a=[...data.pantry].sort((a,b)=>(Number(a.qty)>Number(a.minQty))-(Number(b.qty)>Number(b.minQty)));pantryCount.textContent=a.length;pantryLow.textContent=a.filter(x=>Number(x.qty)<=Number(x.minQty)).length;pantryList.innerHTML=a.map(x=>`<div class="card ${Number(x.qty)<=0?'stock-out':Number(x.qty)<=Number(x.minQty)?'stock-low':''}"><div class="item"><div class="main"><div class="title">${esc(x.name)}</div><div class="meta"><span class="pill">${x.qty} ${esc(x.unit||'')}</span><span>Mínimo ${x.minQty}</span>${x.expiry?`<span>Vence ${x.expiry}</span>`:''}</div></div><button class="mini" onclick="adjustPantry('${x.id}',-1)">−</button><button class="mini" onclick="adjustPantry('${x.id}',1)">＋</button><button class="mini" onclick="openPantryForm('${x.id}')">✎</button></div></div>`).join('')||'<div class="empty">Registra lo que tienen en casa para saber qué reponer.</div>'}
function openPantryForm(id=''){const x=data.pantry.find(v=>v.id===id);pantryForm.reset();pantryFormTitle.textContent=x?'Editar producto':'Producto de despensa';pantryForm.id.value=x?.id||'';pantryForm.name.value=x?.name||'';pantryForm.qty.value=x?.qty??1;pantryForm.minQty.value=x?.minQty??1;pantryForm.unit.value=x?.unit||'unidad';pantryForm.expiry.value=x?.expiry||'';pantryFormModal.classList.add('open')}
pantryForm.onsubmit=e=>{e.preventDefault();const o=Object.fromEntries(new FormData(e.target));o.qty=Number(o.qty);o.minQty=Number(o.minQty);const x=data.pantry.find(v=>v.id===o.id);if(x)Object.assign(x,o);else{o.id=uid();data.pantry.push(o)}closeModal('pantryFormModal');persistUltra();renderPantry();toast('Despensa actualizada')};
function adjustPantry(id,n){const x=data.pantry.find(v=>v.id===id);if(!x)return;x.qty=Math.max(0,Number(x.qty)+n);if(x.qty<=x.minQty&&!data.shopping.some(s=>!s.done&&s.title.toLowerCase()===x.name.toLowerCase()))toast('Producto bajo: puedes añadirlo a compras');persistUltra();renderPantry()}
function openWishlist(){closeModal('ultraModal');wishlistModal.classList.add('open');renderWishlist()}
function renderWishlist(){const pending=data.wishlist.filter(x=>!x.done),total=pending.reduce((s,x)=>s+Number(x.price||0),0);wishTotal.innerHTML=`<div class="budget-top"><div><small>Deseos pendientes</small><strong>${money(total)}</strong></div><span style="font-size:26px">✨</span></div><div class="meta"><span>${pending.length} artículo(s)</span></div>`;wishlistList.innerHTML=data.wishlist.map(x=>`<div class="card"><div class="item"><button class="check ${x.done?'done':''}" onclick="toggleWish('${x.id}')">${x.done?'✓':''}</button><div class="main"><div class="title">${esc(x.title)}</div><div class="wish-price">${money(x.price)}</div><div class="meta"><span class="pill">${esc(x.priority)}</span>${x.note?`<span>${esc(x.note)}</span>`:''}</div></div><button class="mini" onclick="deleteWish('${x.id}')">×</button></div></div>`).join('')||'<div class="empty">Agrega muebles, electrodomésticos, viajes o cualquier meta de compra.</div>'}
function openWishForm(){wishForm.reset();wishFormModal.classList.add('open')}wishForm.onsubmit=e=>{e.preventDefault();const o=Object.fromEntries(new FormData(e.target));o.id=uid();o.price=Number(o.price||0);o.done=false;data.wishlist.push(o);closeModal('wishFormModal');persistUltra();renderWishlist()};function toggleWish(id){const x=data.wishlist.find(v=>v.id===id);x.done=!x.done;persistUltra();renderWishlist()}function deleteWish(id){data.wishlist=data.wishlist.filter(x=>x.id!==id);persistUltra();renderWishlist()}
function openGoals(){closeModal('ultraModal');goalsModal.classList.add('open');renderGoals()}
function renderGoals(){goalsList.innerHTML=data.savingsGoals.map(x=>{const pct=Math.min(100,Math.round(Number(x.saved)/Number(x.target)*100)||0);return`<div class="card"><div class="title">${esc(x.title)}</div><div class="budget-line"><span>${money(x.saved)} ahorrado</span><b>${pct}%</b></div><div class="goalbar"><span style="width:${pct}%"></span></div><div class="meta"><span>Meta ${money(x.target)}</span>${x.date?`<span>Para ${x.date}</span>`:''}</div><button class="text-btn" onclick="addToGoal('${x.id}')">Agregar ahorro</button></div>`}).join('')||'<div class="empty">Crea una meta para muebles, vivienda, viaje o fondo de emergencia.</div>'}
function openGoalForm(){goalForm.reset();goalForm.saved.value=0;goalFormModal.classList.add('open')}goalForm.onsubmit=e=>{e.preventDefault();const o=Object.fromEntries(new FormData(e.target));o.id=uid();o.target=Number(o.target);o.saved=Number(o.saved);data.savingsGoals.push(o);closeModal('goalFormModal');persistUltra();renderGoals()};function addToGoal(id){const x=data.savingsGoals.find(v=>v.id===id),n=prompt('¿Cuánto deseas agregar?',0);if(n!==null&&!isNaN(n)){x.saved=Math.min(Number(x.target),Number(x.saved)+Number(n));persistUltra();renderGoals()}}
function openMeals(){closeModal('ultraModal');mealsModal.classList.add('open');renderMeals()}
function renderMeals(){mealList.innerHTML=weekDays.map(d=>`<div class="meal-row"><b>${d.slice(0,3)}</b><input data-day="${d}" value="${esc(data.mealPlan[d]||'')}" placeholder="Ej. Lomo saltado" onchange="setMeal('${d}',this.value)"><button class="mini" onclick="this.previousElementSibling.value='';setMeal('${d}','')">×</button></div>`).join('')}
function setMeal(d,v){data.mealPlan[d]=v;persistUltra()}
function addMealIngredients(){let count=0;Object.values(data.mealPlan).filter(Boolean).forEach(name=>{const r=RECIPES.find(x=>x.name.toLowerCase()===String(name).toLowerCase());if(r){r.items.forEach(i=>{const p=catalog().find(x=>x.id===i.id);if(!p)return;const ex=data.shopping.find(x=>!x.done&&x.productId===p.id);if(ex)ex.qty+=i.qty;else data.shopping.unshift({id:uid(),title:p.name,productId:p.id,qty:i.qty,unit:p.unit,store:data.preferredStore,assigned:'Ambos',done:false,date:today(),category:p.category});count++})}});save();toast(count?`${count} ingrediente(s) agregados`:'Usa nombres de recetas disponibles en la sección Recetas')}
function openCalendar(){closeModal('ultraModal');calendarModal.classList.add('open');renderCalendar()}
function renderCalendar(){const now=new Date(),days=[];for(let i=0;i<7;i++){const d=new Date(now);d.setDate(now.getDate()+i);const iso=d.toISOString().slice(0,10),has=data.events.some(x=>x.date===iso)||data.fixedExpenses.some(x=>x.active!==false&&Number(x.dueDay)===d.getDate());days.push(`<div class="cal-day ${has?'has':''}">${['Dom','Lun','Mar','Mié','Jue','Vie','Sáb'][d.getDay()]}<b>${d.getDate()}</b></div>`)}calendarSummary.innerHTML=days.join('');const ev=[...data.events].sort((a,b)=>(a.date+a.time).localeCompare(b.date+b.time));eventList.innerHTML=ev.map(x=>`<div class="card"><div class="item"><div class="main"><div class="title">${esc(x.title)}</div><div class="meta"><span class="pill">${x.date} ${x.time||''}</span><span>${esc(x.category)}</span><span>${esc(x.assigned)}</span></div></div><button class="mini" onclick="deleteEvent('${x.id}')">×</button></div></div>`).join('')||'<div class="empty">Agrega citas, pagos, salidas y fechas importantes.</div>'}
function openEventForm(){eventForm.reset();eventForm.date.value=today();eventFormModal.classList.add('open')}eventForm.onsubmit=e=>{e.preventDefault();const o=Object.fromEntries(new FormData(e.target));o.id=uid();data.events.push(o);closeModal('eventFormModal');persistUltra();renderCalendar();scheduleEventNotification(o)};function deleteEvent(id){data.events=data.events.filter(x=>x.id!==id);persistUltra();renderCalendar()}
async function requestNotifications(){if(!('Notification'in window)){alert('Este navegador no admite notificaciones web.');return}const r=await Notification.requestPermission();toast(r==='granted'?'Notificaciones activadas':'Permiso no concedido')}
function scheduleEventNotification(o){if(Notification.permission==='granted'){const t=new Date(`${o.date}T${o.time||'09:00'}`).getTime()-Date.now();if(t>0&&t<2147483647)setTimeout(()=>new Notification('Nuestro Espacio',{body:o.title}),t)}}
let scanStream=null,scanTimer=null;function openScanner(){closeModal('ultraModal');scannerModal.classList.add('open')}async function startScanner(){try{scanStream=await navigator.mediaDevices.getUserMedia({video:{facingMode:'environment'}});scanVideo.srcObject=scanStream;await scanVideo.play();scanStatus.textContent='Buscando código…';if('BarcodeDetector'in window){const detector=new BarcodeDetector({formats:['ean_13','ean_8','upc_a','upc_e','code_128']});scanTimer=setInterval(async()=>{try{const codes=await detector.detect(scanVideo);if(codes[0]){manualBarcode.value=codes[0].rawValue;scanStatus.textContent='Código detectado: '+codes[0].rawValue;stopScanner()}}catch{}},600)}else scanStatus.textContent='La cámara funciona, pero este navegador no tiene detección automática. Ingresa el código manualmente.'}catch(e){scanStatus.textContent='No se pudo abrir la cámara. Revisa los permisos o usa el código manual.'}}
function stopScanner(){clearInterval(scanTimer);scanTimer=null;if(scanStream){scanStream.getTracks().forEach(t=>t.stop());scanStream=null}scanVideo.srcObject=null}
function useBarcode(){const code=manualBarcode.value.trim();if(!code)return alert('Ingresa un código.');const known=data.barcodes[code];if(known){closeModal('scannerModal');openForm('shopping');setTimeout(()=>{productInput.value=known.name||known;productInput.dispatchEvent(new Event('input'))},50)}else{const name=prompt('Producto no registrado. ¿Cómo se llama?');if(name){data.barcodes[code]={name};persistUltra();closeModal('scannerModal');openForm('shopping');setTimeout(()=>productInput.value=name,50)}}}
function openShare(){closeModal('ultraModal');shareModal.classList.add('open');quickSyncCode.textContent=btoa(unescape(encodeURIComponent(JSON.stringify({budget:data.budget,preferredStore:data.preferredStore,theme:data.theme})))).slice(0,500)}function copyQuickCode(){navigator.clipboard?.writeText(quickSyncCode.textContent);toast('Código copiado')}
