const APP_VERSION='4.0.1';
const APP_BUILD='13/07/2026 04:25 (Lima)';
function compareVersions(a,b){const pa=String(a).split('.').map(Number),pb=String(b).split('.').map(Number);for(let i=0;i<Math.max(pa.length,pb.length);i++){const x=pa[i]||0,y=pb[i]||0;if(x>y)return 1;if(x<y)return -1}return 0}
function setVersionStatus(text,type=''){const el=document.getElementById('versionStatus');if(!el)return;el.textContent=text;el.className='version-status'+(type?' '+type:'')}
async function checkForUpdate(manual=false){
 if(location.protocol==='file:'){setVersionStatus(`Versión ${APP_VERSION} · ${APP_BUILD} · Abierto como archivo local`,'warn');if(manual)toast('La comprobación automática funciona desde GitHub Pages');return}
 setVersionStatus('Buscando una versión más reciente…');
 try{const url=new URL(location.href);url.searchParams.set('_versionCheck',Date.now());const r=await fetch(url.toString(),{cache:'no-store'});if(!r.ok)throw new Error('HTTP '+r.status);const text=await r.text();const m=text.match(/<meta name="app-version" content="([^"]+)"/i);const b=text.match(/<meta name="app-build" content="([^"]+)"/i);if(!m)throw new Error('Versión no encontrada');const remote=m[1],remoteBuild=b?.[1]||'';const cmp=compareVersions(remote,APP_VERSION);if(cmp>0){setVersionStatus(`Nueva versión disponible: v${remote} · ${remoteBuild}. Recarga la página.`,'warn');if(manual)toast(`Nueva versión v${remote} disponible`)}else{setVersionStatus(`Estás al día · v${APP_VERSION} · ${APP_BUILD}`,'ok');if(manual)toast('Tienes la versión más reciente')}}catch(e){setVersionStatus(`No se pudo comprobar ahora · v${APP_VERSION} · ${APP_BUILD}`,'error');if(manual)toast('No se pudo verificar la actualización')}
}
window.addEventListener('load',()=>{setTimeout(()=>checkForUpdate(false),1200)});

// === PWA v3: instalación, offline y actualización segura ===
let deferredInstallPrompt=null;
const isStandalone=()=>window.matchMedia('(display-mode: standalone)').matches||window.navigator.standalone===true;
function refreshInstallUI(){
 const card=document.getElementById('pwaInstallCard'),btn=document.getElementById('installAppBtn');
 if(!card||!btn)return;
 if(isStandalone()){card.style.display='none';return}
 card.style.display='block';
 btn.textContent=deferredInstallPrompt?'Instalar aplicación':'Instalar / ver instrucciones';
}
window.addEventListener('beforeinstallprompt',e=>{e.preventDefault();deferredInstallPrompt=e;refreshInstallUI()});
window.addEventListener('appinstalled',()=>{deferredInstallPrompt=null;refreshInstallUI();toast?.('Nuestro Espacio quedó instalado')});
async function installPWA(){
 if(deferredInstallPrompt){deferredInstallPrompt.prompt();await deferredInstallPrompt.userChoice;deferredInstallPrompt=null;refreshInstallUI();return}
 showInstallHelp();
}
function showInstallHelp(){
 const ios=/iphone|ipad|ipod/i.test(navigator.userAgent);
 alert(ios?'En Safari: toca Compartir (cuadrado con flecha) → Agregar a pantalla de inicio → Agregar.':'En Chrome: abre el menú ⋮ y selecciona “Instalar aplicación” o “Agregar a pantalla principal”.');
}
document.getElementById('installAppBtn')?.addEventListener('click',installPWA);
document.getElementById('installHelpBtn')?.addEventListener('click',showInstallHelp);
function updateOnlineState(){document.getElementById('offlineBanner')?.classList.toggle('show',!navigator.onLine)}
window.addEventListener('online',()=>{updateOnlineState();toast?.('Conexión recuperada')});
window.addEventListener('offline',()=>{updateOnlineState();toast?.('Modo sin conexión activo')});
updateOnlineState();refreshInstallUI();
if('serviceWorker' in navigator && location.protocol!=='file:'){
 window.addEventListener('load',async()=>{
  try{
   const reg=await navigator.serviceWorker.register('./sw.js',{scope:'./'});
   reg.addEventListener('updatefound',()=>{
    const worker=reg.installing;if(!worker)return;
    worker.addEventListener('statechange',()=>{
     if(worker.state==='installed'&&navigator.serviceWorker.controller){
      setVersionStatus?.('Nueva versión descargada. Recarga para aplicarla.','warn');
      toast?.('Actualización lista para instalar');
     }
    });
   });
   navigator.serviceWorker.addEventListener('controllerchange',()=>{if(!window.__pwaReloading){window.__pwaReloading=true;location.reload()}});
  }catch(e){console.warn('Service Worker no disponible',e)}
 });
}



